Perform the necessary pre-checks and then compute:


If Z=1{Z = 1}Z=1 then every number is divisible by Z{Z}Z so output −1{-1}−1.
If Ymod  Z=0{Y \mod Z = 0}YmodZ=0 then every multiple of Y{Y}Y will be divisible by Z{Z}Z so output −1{-1}−1.
Set
m=⌊XY⌋+1.m = \left\lfloor \frac{X}{Y} \right\rfloor + 1.m=⌊YX​⌋+1.

Compute g=gcd⁡(Y,Z){g = \gcd(Y, Z)}g=gcd(Y,Z) and d=Zg{d = \frac{Z}{g}}d=gZ​.
If mmod  d=0{m \mod d = 0}mmodd=0 then increment m{m}m by 111.
Finally, output K=Ytimesm{K = Y times m}K=Ytimesm.
This method relies on straightforward number theory and performs only constant-time computations per query.

**Code Implementation in C++:**

`#include &lt;iostream&gt;
#include &lt;numeric&gt;
#include &lt;algorithm&gt;
#include &lt;string&gt;
using namespace std;

// Function to convert __int128 to string for output.
string int128ToString(__int128 num) {
    if(num == 0) return "0";
    bool neg = false;
    if(num &lt; 0) { neg = true; num = -num; }
    string s;
    while(num &gt; 0) {
        int digit = (int)(num % 10);
        s.push_back('0' + digit);
        num /= 10;
    }
    if(neg) s.push_back('-');
    reverse(s.begin(), s.end());
    return s;
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin &gt;&gt; t;
    while(t--){
        unsigned long long X, Y, Z;
        cin &gt;&gt; X &gt;&gt; Y &gt;&gt; Z;

        if(Z == 1ULL){
            cout &lt;&lt; -1 &lt;&lt; "\n";
            continue;
        }

        if(Y % Z == 0ULL){
            cout &lt;&lt; -1 &lt;&lt; "\n";
            continue;
        }

        // Compute m0: smallest integer m such that Y*m &gt; X.
        unsigned long long m = (X / Y) + 1;

        // Let g = gcd(Y, Z) and compute d = Z / g.
        unsigned long long g = std::gcd(Y, Z);
        unsigned long long d = Z / g;

        // If m is divisible by d, adjust by incrementing m.
        if(m % d == 0ULL)
            m++;

        __int128 K = (__int128) Y * m;
        cout &lt;&lt; int128ToString(K) &lt;&lt; "\n";
    }
    return 0;
}
